"use client";

import { useEffect, useState } from "react";
import { useAuth } from "@/context/AuthContext";
import { useRouter } from "next/navigation";
import Navbar from "@/components/Navbar";
import api from "@/lib/api";
import { User, Bell, QrCode, LogOut } from "lucide-react";

export default function Home() {
    const { user, loading, logout } = useAuth();
    const router = useRouter();
    const [balance, setBalance] = useState(0);
    const [history, setHistory] = useState([]);

    useEffect(() => {
        if (!loading && !user) {
            router.push("/login");
        }
    }, [user, loading, router]);

    useEffect(() => {
        if (user) {
            fetchData();
        }
    }, [user]);

    const fetchData = async () => {
        try {
            const [balRes, histRes] = await Promise.all([
                api.get("/wallet/balance"),
                api.get("/transfer/history?limit=5"),
            ]);
            setBalance(balRes.data.data.balance);
            setHistory(histRes.data.data.transactions);
        } catch (err) {
            console.error("Failed to fetch dashboard data");
        }
    };

    if (loading || !user) {
        return (
            <div className="flex items-center justify-center min-h-screen bg-black">
                <div className="w-12 h-12 border-4 border-cashapp border-t-transparent rounded-full animate-spin" />
            </div>
        );
    }

    return (
        <div className="pb-24 pt-8 px-6 min-h-screen flex flex-col bg-white dark:bg-black">
            {/* Header */}
            <div className="flex items-center justify-between mb-12">
                <button onClick={logout} className="p-2 bg-gray-50 dark:bg-zinc-900 rounded-full hover:bg-red-50 dark:hover:bg-red-900/20 text-gray-500 hover:text-red-500 transition-all">
                    <LogOut className="w-6 h-6" />
                </button>
                <div className="flex items-center space-x-2">
                    <QrCode className="w-6 h-6 text-gray-400" />
                    <div className="w-10 h-10 bg-cashapp/10 rounded-full flex items-center justify-center">
                        <User className="w-6 h-6 text-cashapp" />
                    </div>
                </div>
            </div>

            {/* Balance Section */}
            <div className="flex-1 flex flex-col items-center justify-center -translate-y-8">
                <p className="text-gray-500 font-bold tracking-widest uppercase text-xs mb-2">Total Balance</p>
                <h2 className="text-7xl font-bold tracking-tight">
                    ${(balance / 100).toLocaleString(undefined, { minimumFractionDigits: 2 })}
                </h2>

                <div className="flex space-x-4 mt-12 w-full max-w-xs">
                    <button className="flex-1 bg-cashapp text-white font-bold py-4 rounded-xl shadow-lg shadow-cashapp/20 hover:scale-105 active:scale-95 transition-all">
                        Add Cash
                    </button>
                    <button className="flex-1 bg-gray-50 dark:bg-zinc-900 font-bold py-4 rounded-xl hover:scale-105 active:scale-95 transition-all">
                        Cash Out
                    </button>
                </div>
            </div>

            {/* Recent Activity */}
            <div className="mt-auto">
                <div className="flex items-center justify-between mb-4">
                    <h3 className="font-bold text-lg">Activity</h3>
                    <button onClick={() => router.push('/activity')} className="text-cashapp text-sm font-bold">See All</button>
                </div>
                <div className="space-y-4">
                    {history.length > 0 ? history.map((tx) => (
                        <div key={tx.id} className="flex items-center justify-between p-4 bg-gray-50 dark:bg-zinc-900 rounded-2xl">
                            <div className="flex items-center space-x-4">
                                <div className="w-12 h-12 bg-white dark:bg-black rounded-full flex items-center justify-center font-bold text-cashapp">
                                    {tx.type === 'send' ? 'S' : 'R'}
                                </div>
                                <div>
                                    <p className="font-bold">{tx.type === 'send' ? 'Paid to' : 'Received from'} {tx.note || 'Transfer'}</p>
                                    <p className="text-xs text-gray-500 uppercase font-medium">{new Date(tx.created_at).toLocaleDateString()}</p>
                                </div>
                            </div>
                            <p className={tx.type === 'send' ? 'font-bold' : 'font-bold text-cashapp'}>
                                {tx.type === 'send' ? '-' : '+'}${(tx.amount / 100).toFixed(2)}
                            </p>
                        </div>
                    )) : (
                        <p className="text-center text-gray-500 py-8">No recent transactions</p>
                    )}
                </div>
            </div>

            <Navbar />
        </div>
    );
}
